import{D as e,d as t,l as n}from"./runtime-core.esm-bundler-BkUJkfAY.js";import{t as r}from"./plugin-vue_export-helper-CwH_LPhl.js";var i=JSON.parse(`{"path":"/%E5%89%8D%E7%AB%AF%E5%BC%80%E5%8F%91/JavaScript%E6%95%99%E7%A8%8B/01.%E5%9F%BA%E7%A1%80.html","title":"基础","lang":"zh-CN","frontmatter":{"title":"基础","date":"2020-01-12T11:49:16.000Z","category":["《JavaScript教程》笔记"],"tag":["JavaScript"],"author":"Mokylp","order":1},"git":{"createdTime":1775202256000,"updatedTime":1775203190000,"contributors":[{"name":"moklgy","username":"moklgy","email":"moklgy@foxmail.com","commits":2,"url":"https://github.com/moklgy"}]},"readingTime":{"minutes":16.94,"words":5082},"filePathRelative":"前端开发/JavaScript教程/01.基础.md","excerpt":"<blockquote>\\n<p>说明：本章内容为博主在原教程基础上添加自己的学习笔记，来源<a href=\\"https://wangdoc.com/javascript/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">https://wangdoc.com/javascript/</a>，教程版权归原作者所有。</p>\\n</blockquote>\\n<h1>基础篇</h1>\\n<h2>一、JS的一些名词概念</h2>\\n<h4>什么是作用域？</h4>\\n<p>变量存在的范围。</p>\\n<p>可分为全局作用域和函数作用域，ES6新增块级作用域。</p>\\n<h4>什么是闭包？</h4>"}`),a={name:`01.基础.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<blockquote><p>说明：本章内容为博主在原教程基础上添加自己的学习笔记，来源<a href="https://wangdoc.com/javascript/" target="_blank" rel="noopener noreferrer">https://wangdoc.com/javascript/</a>，教程版权归原作者所有。</p></blockquote><h1 id="基础篇" tabindex="-1"><a class="header-anchor" href="#基础篇"><span>基础篇</span></a></h1><h2 id="一、js的一些名词概念" tabindex="-1"><a class="header-anchor" href="#一、js的一些名词概念"><span>一、JS的一些名词概念</span></a></h2><h4 id="什么是作用域" tabindex="-1"><a class="header-anchor" href="#什么是作用域"><span>什么是作用域？</span></a></h4><p>变量存在的范围。</p><p>可分为全局作用域和函数作用域，ES6新增块级作用域。</p><h4 id="什么是闭包" tabindex="-1"><a class="header-anchor" href="#什么是闭包"><span>什么是闭包？</span></a></h4><p>闭包就是能够读取其他函数内部变量的函数。</p><ul><li>闭包的形式：函数内部定义函数</li><li>本质上闭包就是将函数内部和外部连接起来的一座桥梁</li></ul><p>闭包的作用：</p><ul><li>可以读取函数内部变量</li><li>让这些变量始终保持在内存中，即闭包可以使得它诞生的环境一直存在。</li><li>封装对象的私有属性和私有方法</li></ul><h4 id="什么是构造函数" tabindex="-1"><a class="header-anchor" href="#什么是构造函数"><span>什么是构造函数？</span></a></h4><p>用于构造(生成)实例的一个函数，使实例拥有构造函数内定于的属性和方法。</p><h4 id="什么是实例对象" tabindex="-1"><a class="header-anchor" href="#什么是实例对象"><span>什么是实例对象？</span></a></h4><p>实例对象就是通过new 构造函数生成的，拥有构造函数内定于的属性和方法的一个对象。</p><h4 id="什么是this" tabindex="-1"><a class="header-anchor" href="#什么是this"><span>什么是this？</span></a></h4><p>就是属性或方法当前所在的对象，指向当前运行环境（对象）</p><h4 id="什么是原型" tabindex="-1"><a class="header-anchor" href="#什么是原型"><span>什么是原型？</span></a></h4><p>每个函数都有一个prototype属性，指向一个对象，该对象称为原型对象。</p><h4 id="什么是原型链" tabindex="-1"><a class="header-anchor" href="#什么是原型链"><span>什么是原型链？</span></a></h4><p>所有对象都有自己的原型对象，由于原型对象也是对象，因此它也有自己的原型，这就会形成一个原型链。</p><p>最顶层的原型是Object.prototype。</p><blockquote><p>读取对象属性时，JS会先在对象自身上找，找到就直接返回，如果找不到，会到原型上找，如果还是找不到，就会去原型的原型上找，最终会到最顶层的Object.prototype上找，还是找不到就会返回undefined。</p></blockquote><h4 id="什么是constructor" tabindex="-1"><a class="header-anchor" href="#什么是constructor"><span>什么是constructor？</span></a></h4><p>prototype原型对象都有一个constructor属性，默认指向prototype对象所在的构造函数。</p><h4 id="什么是包装对象" tabindex="-1"><a class="header-anchor" href="#什么是包装对象"><span>什么是包装对象？</span></a></h4><p>包装对象指的是将原始类型（数字、字符串、布尔值）进行实例化。</p><h2 id="二、数据类型的转换" tabindex="-1"><a class="header-anchor" href="#二、数据类型的转换"><span>二、数据类型的转换</span></a></h2><h3 id="_1、强制-手动-转换" tabindex="-1"><a class="header-anchor" href="#_1、强制-手动-转换"><span>1、强制（手动）转换</span></a></h3><p>强制转换主要指使用<code>Number()</code>、<code>String()</code>和<code>Boolean()</code>三个函数，手动将各种类型的值，分别转换成<strong>数字、字符串、布尔值</strong>。</p><h4 id="number" tabindex="-1"><a class="header-anchor" href="#number"><span>Number()</span></a></h4><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 数值：转换后还是原来的值</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">324</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 324</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 字符串：如果可以被解析为数值，则转换为相应的数值</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;324&#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 324</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 字符串：如果不可以被解析为数值，返回 NaN</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;324abc&#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 空字符串转为0</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;&#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 布尔值：true 转成 1，false 转成 0</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">true</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 1</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// undefined：转成 NaN</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">undefined</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// null：转成0</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">null</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">({</span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">}) </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">([</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">]) </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">([</span><span style="color:#D19A66;">5</span><span style="color:#ABB2BF;">]) </span><span style="color:#7F848E;font-style:italic;">// 5</span></span>
<span class="line"><span style="color:#61AFEF;">Number</span><span style="color:#ABB2BF;">([]) </span><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//使用parseInt()转数组</span></span>
<span class="line"><span style="color:#61AFEF;">parseInt</span><span style="color:#ABB2BF;">([</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">]) </span><span style="color:#7F848E;font-style:italic;">// 1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="string" tabindex="-1"><a class="header-anchor" href="#string"><span>String()</span></a></h4><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 原始类型的转换</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">123</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// &quot;123&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;abc&#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// &quot;abc&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">true</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// &quot;true&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">undefined</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// &quot;undefined&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">null</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// &quot;null&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 对象的转换</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">({</span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">}) </span><span style="color:#7F848E;font-style:italic;">// &quot;[object Object]&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">([</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">]) </span><span style="color:#7F848E;font-style:italic;">// &quot;1,2,3&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">([]) </span><span style="color:#7F848E;font-style:italic;">// &quot;&quot;  空字符串</span></span>
<span class="line"><span style="color:#61AFEF;">String</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;">(){}) </span><span style="color:#7F848E;font-style:italic;">// &quot;function(){}&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="boolean" tabindex="-1"><a class="header-anchor" href="#boolean"><span>Boolean()</span></a></h4><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 除了这五个为false，其他都为true</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">undefined</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// false</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">null</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// false</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// false</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">NaN</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// false</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;&#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// false</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//true</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">({}) </span><span style="color:#7F848E;font-style:italic;">// true</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">([]) </span><span style="color:#7F848E;font-style:italic;">// true</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">new</span><span style="color:#61AFEF;"> Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">false</span><span style="color:#ABB2BF;">)) </span><span style="color:#7F848E;font-style:italic;">// true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// true</span></span>
<span class="line"><span style="color:#61AFEF;">Boolean</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39; &#39;</span><span style="color:#ABB2BF;">) </span><span style="color:#7F848E;font-style:italic;">// true // 注意字符串内有个空格</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2、自动转换" tabindex="-1"><a class="header-anchor" href="#_2、自动转换"><span>2、自动转换</span></a></h3><p>下面介绍自动转换，它是<strong>以强制转换为基础的</strong>。</p><p>遇到以下三种情况时，JavaScript 会自动转换数据类型，即转换是自动完成的，用户不可见。</p><p>第一种情况，<strong>不同类型的数据互相运算</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#D19A66;">123</span><span style="color:#56B6C2;"> +</span><span style="color:#98C379;"> &#39;abc&#39;</span><span style="color:#7F848E;font-style:italic;"> // &quot;123abc&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>第二种情况，<strong>对非布尔值类型的数据求布尔值</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#98C379;">&#39;abc&#39;</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;hello&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#ABB2BF;">}  </span><span style="color:#7F848E;font-style:italic;">// &quot;hello&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>第三种情况，<strong>对非数值类型的值使用一元运算符（即<code>+</code>和<code>-</code>）</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#56B6C2;">+</span><span style="color:#ABB2BF;"> {</span><span style="color:#E06C75;">foo</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&#39;bar&#39;</span><span style="color:#ABB2BF;">} </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span>
<span class="line"><span style="color:#56B6C2;">-</span><span style="color:#ABB2BF;"> [</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">] </span><span style="color:#7F848E;font-style:italic;">// NaN</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>自动转换的规则是这样的：预期什么类型的值，就调用该类型的转换函数。比如，某个位置预期为字符串，就调用<code>String</code>函数进行转换。如果该位置即可以是字符串，也可能是数值，那么默认转为数值。</p><p>由于自动转换具有不确定性，而且不易除错，建议在预期为布尔值、数值、字符串的地方，全部使用<code>Boolean</code>、<code>Number</code>和<code>String</code>函数进行显式转换。</p><h4 id="自动转换为布尔值-boolean" tabindex="-1"><a class="header-anchor" href="#自动转换为布尔值-boolean"><span>自动转换为布尔值（Boolean）</span></a></h4><p>JavaScript 遇到预期为布尔值的地方（比如<code>if</code>语句的条件部分），就会将非布尔值的参数自动转换为布尔值。系统内部会自动调用<code>Boolean</code>函数。</p><p>因此除了以下五个值，其他都是自动转为<code>true</code>。</p><ul><li><code>undefined</code></li><li><code>null</code></li><li><code>+0</code>或<code>-0</code></li><li><code>NaN</code></li><li><code>&#39;&#39;</code>（空字符串）</li></ul><p>下面这个例子中，条件部分的每个值都相当于<code>false</code>，使用否定运算符后，就变成了<code>true</code>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> ( </span><span style="color:#56B6C2;">!</span><span style="color:#D19A66;">undefined</span></span>
<span class="line"><span style="color:#56B6C2;">  &amp;&amp;</span><span style="color:#56B6C2;"> !</span><span style="color:#D19A66;">null</span></span>
<span class="line"><span style="color:#56B6C2;">  &amp;&amp;</span><span style="color:#56B6C2;"> !</span><span style="color:#D19A66;">0</span></span>
<span class="line"><span style="color:#56B6C2;">  &amp;&amp;</span><span style="color:#56B6C2;"> !</span><span style="color:#D19A66;">NaN</span></span>
<span class="line"><span style="color:#56B6C2;">  &amp;&amp;</span><span style="color:#56B6C2;"> !</span><span style="color:#98C379;">&#39;&#39;</span></span>
<span class="line"><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;true&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#7F848E;font-style:italic;">// true</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>下面两种写法，有时也用于将一个表达式转为布尔值。它们内部调用的也是<code>Boolean</code>函数。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 三元运算符</span></span>
<span class="line"><span style="color:#E06C75;">expression</span><span style="color:#C678DD;"> ?</span><span style="color:#D19A66;"> true</span><span style="color:#C678DD;"> :</span><span style="color:#D19A66;"> false</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 取反运算符</span></span>
<span class="line"><span style="color:#56B6C2;">!!</span><span style="color:#E06C75;"> expression</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="自动转换为字符串-string" tabindex="-1"><a class="header-anchor" href="#自动转换为字符串-string"><span>自动转换为字符串（String）</span></a></h4><p>JavaScript 遇到预期为字符串的地方，就会将非字符串的值自动转为字符串。<strong>具体规则是，先将复合类型的值转为原始类型的值，再将原始类型的值转为字符串</strong>。</p><p>字符串的自动转换，<strong>主要发生在字符串的加法运算时</strong>。当一个值为字符串，另一个值为非字符串，则后者转为字符串。</p><h5 id="所有类型的值与字符串相加都会变成字符串" tabindex="-1"><a class="header-anchor" href="#所有类型的值与字符串相加都会变成字符串"><span>所有类型的值与字符串相加都会变成字符串</span></a></h5><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;"> // &#39;51&#39;</span></span>
<span class="line"><span style="color:#D19A66;"> 1</span><span style="color:#56B6C2;">  +</span><span style="color:#98C379;"> &#39;5&#39;</span><span style="color:#7F848E;font-style:italic;"> // &#39;15&#39;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> true</span><span style="color:#7F848E;font-style:italic;"> // &quot;5true&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> false</span><span style="color:#7F848E;font-style:italic;"> // &quot;5false&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#ABB2BF;"> {} </span><span style="color:#7F848E;font-style:italic;">// &quot;5[object Object]&quot;</span></span>
<span class="line"><span style="color:#D19A66;"> 5</span><span style="color:#56B6C2;"> +</span><span style="color:#ABB2BF;"> {} </span><span style="color:#7F848E;font-style:italic;">// &quot;5[object Object]&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#ABB2BF;"> [] </span><span style="color:#7F848E;font-style:italic;">// &quot;5&quot;</span></span>
<span class="line"><span style="color:#D19A66;"> 5</span><span style="color:#56B6C2;"> +</span><span style="color:#ABB2BF;"> [] </span><span style="color:#7F848E;font-style:italic;">// &quot;5&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#C678DD;"> function</span><span style="color:#ABB2BF;"> (){} </span><span style="color:#7F848E;font-style:italic;">// &quot;5function (){}&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> undefined</span><span style="color:#7F848E;font-style:italic;"> // &quot;5undefined&quot;</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> null</span><span style="color:#7F848E;font-style:italic;"> // &quot;5null&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="" tabindex="-1"><a class="header-anchor" href="#"><span></span></a></h5><p>这种自动转换不注意的话很容易出错。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> obj</span><span style="color:#56B6C2;"> =</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">  width</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&#39;100&#39;</span></span>
<span class="line"><span style="color:#ABB2BF;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">obj</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">width</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> 20</span><span style="color:#7F848E;font-style:italic;"> // &quot;10020&quot;</span></span>
<span class="line"><span style="color:#61AFEF;">parerInt</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">obj</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">width</span><span style="color:#ABB2BF;">) </span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;"> 20</span><span style="color:#7F848E;font-style:italic;"> // 120</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，开发者可能期望返回<code>120</code>，但是由于自动转换，实际上返回了一个字符<code>10020</code>。正确做法是先把字符串转成数字。</p><h4 id="自动转换为数值-number" tabindex="-1"><a class="header-anchor" href="#自动转换为数值-number"><span>自动转换为数值（Number）</span></a></h4><p>JavaScript 遇到预期为数值的地方，就会将参数值自动转换为数值。系统内部会自动调用<code>Number</code>函数。</p><h5 id="除加号与字符串运行会转成字符串外-其他运行基本都会自动转成数值" tabindex="-1"><a class="header-anchor" href="#除加号与字符串运行会转成字符串外-其他运行基本都会自动转成数值"><span>除加号与字符串运行会转成字符串外，其他运行基本都会自动转成数值</span></a></h5><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> -</span><span style="color:#98C379;"> &#39;2&#39;</span><span style="color:#7F848E;font-style:italic;"> // 3</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> *</span><span style="color:#98C379;"> &#39;2&#39;</span><span style="color:#7F848E;font-style:italic;"> // 10</span></span>
<span class="line"><span style="color:#D19A66;">true</span><span style="color:#56B6C2;"> -</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;">  // 0</span></span>
<span class="line"><span style="color:#D19A66;">false</span><span style="color:#56B6C2;"> -</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;"> // -1</span></span>
<span class="line"><span style="color:#98C379;">&#39;1&#39;</span><span style="color:#56B6C2;"> -</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;">   // 0</span></span>
<span class="line"><span style="color:#98C379;">&#39;5&#39;</span><span style="color:#56B6C2;"> *</span><span style="color:#ABB2BF;"> []    </span><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"><span style="color:#D19A66;">false</span><span style="color:#56B6C2;"> /</span><span style="color:#98C379;"> &#39;5&#39;</span><span style="color:#7F848E;font-style:italic;"> // 0</span></span>
<span class="line"><span style="color:#98C379;">&#39;abc&#39;</span><span style="color:#56B6C2;"> -</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;">   // NaN</span></span>
<span class="line"><span style="color:#D19A66;">null</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;"> // 1</span></span>
<span class="line"><span style="color:#D19A66;">undefined</span><span style="color:#56B6C2;"> +</span><span style="color:#D19A66;"> 1</span><span style="color:#7F848E;font-style:italic;"> // NaN</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D19A66;">true</span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">true</span><span style="color:#7F848E;font-style:italic;"> // 2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，运算符两侧的运算子，都被转成了数值。</p><blockquote><p>注意：<code>null</code>转为数值时为<code>0</code>，而<code>undefined</code>转为数值时为<code>NaN</code>。</p></blockquote><p><strong>数值与布尔值、null也会转为数值</strong></p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#D19A66;">5</span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">true</span><span style="color:#7F848E;font-style:italic;"> // 6</span></span>
<span class="line"><span style="color:#D19A66;">5</span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">false</span><span style="color:#7F848E;font-style:italic;"> // 5</span></span>
<span class="line"><span style="color:#D19A66;">5</span><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">null</span><span style="color:#7F848E;font-style:italic;"> //5</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>一元运算符也会把运算子转成数值。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#56B6C2;">+</span><span style="color:#98C379;">&#39;abc&#39;</span><span style="color:#7F848E;font-style:italic;"> // NaN</span></span>
<span class="line"><span style="color:#56B6C2;">-</span><span style="color:#98C379;">&#39;abc&#39;</span><span style="color:#7F848E;font-style:italic;"> // NaN</span></span>
<span class="line"><span style="color:#56B6C2;">+</span><span style="color:#D19A66;">true</span><span style="color:#7F848E;font-style:italic;"> // 1</span></span>
<span class="line"><span style="color:#56B6C2;">-</span><span style="color:#D19A66;">false</span><span style="color:#7F848E;font-style:italic;"> // 0</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="三、错误处理机制" tabindex="-1"><a class="header-anchor" href="#三、错误处理机制"><span>三、错误处理机制</span></a></h2><h3 id="_1、error实例对象" tabindex="-1"><a class="header-anchor" href="#_1、error实例对象"><span>1、Error实例对象</span></a></h3><p>JavaScript 解析或运行时，一旦发生错误，引擎就会抛出一个错误对象。JavaScript 原生提供<code>Error</code>构造函数，所有抛出的错误都是这个构造函数的实例。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> err</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">err</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#7F848E;font-style:italic;"> // &quot;出错了&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，我们调用<code>Error</code>构造函数，生成一个实例对象<code>err</code>。<code>Error</code>构造函数接受一个参数，表示错误提示，可以从实例的<code>message</code>属性读到这个参数。<strong>抛出<code>Error</code>实例对象以后，整个程序就中断在发生错误的地方，不再往下执行</strong>。</p><p>JavaScript 语言标准只提到，<code>Error</code>实例对象必须有<code>message</code>属性，表示出错时的提示信息，没有提到其他属性。大多数 JavaScript 引擎，对<code>Error</code>实例还提供<code>name</code>和<code>stack</code>属性，分别表示错误的名称和错误的堆栈，但它们是非标准的，不是每种实现都有。</p><ul><li><strong>message</strong>：错误提示信息</li><li><strong>name</strong>：错误名称（非标准属性）</li><li><strong>stack</strong>：错误的堆栈（非标准属性）</li></ul><p>使用<code>name</code>和<code>message</code>这两个属性，可以对发生什么错误有一个大概的了解。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> err</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E5C07B;">err</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">err</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> +</span><span style="color:#98C379;"> &#39;: &#39;</span><span style="color:#56B6C2;"> +</span><span style="color:#E5C07B;"> err</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// Error: 出错了</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>stack</code>属性用来查看错误发生时的堆栈。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> throwit</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  throw</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> catchit</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">    throwit</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">stack</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// print stack trace</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">catchit</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Error</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at throwit (~/examples/throwcatch.js:9:11) // 堆栈的最内层throwit函数</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at catchit (~/examples/throwcatch.js:3:9) // 向外一层catchit函数</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at repl:1:5 // 函数的运行环境</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 堆栈信息说明</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Error 错误</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at throwit 在throwit方法 (~/examples/throwcatch.js:9:11) 文件名：第几行：第几个字符</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at catchit 在catchit方法 (~/examples/throwcatch.js:3:9) 文件名：第几行：第几个字符</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at repl:1:5 // 函数的运行环境</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，错误堆栈的最内层是<code>throwit</code>函数，然后是<code>catchit</code>函数，最后是函数的运行环境。</p><h3 id="_2、原生错误类型" tabindex="-1"><a class="header-anchor" href="#_2、原生错误类型"><span>2、原生错误类型</span></a></h3><p><code>Error</code>实例对象是最一般的错误类型，在它的基础上，JavaScript 还定义了其他6种错误对象。也就是说，存在<code>Error</code>的6个派生对象。</p><h4 id="syntaxerror-对象-语法错误" tabindex="-1"><a class="header-anchor" href="#syntaxerror-对象-语法错误"><span>SyntaxError 对象（语法错误）</span></a></h4><p><code>SyntaxError</code>对象是解析代码时发生的<strong>语法错误</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 变量名错误</span></span>
<span class="line"><span style="color:#C678DD;">var</span><span style="color:#ABB2BF;"> 1</span><span style="color:#E06C75;">a</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught SyntaxError: Invalid or unexpected token</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 语法错误：无效或意外的标记符号</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 缺少括号</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">log</span><span style="color:#98C379;"> &#39;hello&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught SyntaxError: Unexpected string</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 语法错误：意外的字符串</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码的错误，都是在语法解析阶段就可以发现，所以会抛出<code>SyntaxError</code>。第一个错误提示是“token 非法”，第二个错误提示是“字符串不符合要求”。</p><h4 id="referenceerror-对象-引用错误" tabindex="-1"><a class="header-anchor" href="#referenceerror-对象-引用错误"><span>ReferenceError 对象（引用错误）</span></a></h4><p><code>ReferenceError</code>对象是<strong>引用一个不存在的变量时发生的错误</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 使用一个不存在的变量</span></span>
<span class="line"><span style="color:#E06C75;">unknownVariable</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught ReferenceError: unknownVariable is not defined</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 引用错误： unknownVariable 没有定义</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>另一种触发场景是，将一个值分配给无法分配的对象，比如对函数的运行结果或者<code>this</code>赋值。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 等号左侧不是变量</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">() </span><span style="color:#56B6C2;">=</span><span style="color:#D19A66;"> 1</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught ReferenceError: Invalid left-hand side in assignment</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 引用错误： 赋值中左边是无效的</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// this 对象不能手动赋值</span></span>
<span class="line"><span style="color:#E5C07B;">this</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> 1</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// ReferenceError: Invalid left-hand side in assignment</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 引用错误：  赋值中左边是无效的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码对函数<code>console.log</code>的运行结果和<code>this</code>赋值，结果都引发了<code>ReferenceError</code>错误。</p><h4 id="rangeerror-对象-范围错误" tabindex="-1"><a class="header-anchor" href="#rangeerror-对象-范围错误"><span>RangeError 对象（范围错误）</span></a></h4><p><code>RangeError</code>对象是一个值<strong>超出有效范围时发生的错误</strong>。主要有几种情况，一是数组长度为负数，二是<code>Number</code>对象的方法参数超出范围，以及函数堆栈超过最大值。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 数组长度不得为负数</span></span>
<span class="line"><span style="color:#C678DD;">new</span><span style="color:#61AFEF;"> Array</span><span style="color:#ABB2BF;">(</span><span style="color:#56B6C2;">-</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught RangeError: Invalid array length</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 范围错误：无效的数组长度</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="typeerror-对象-类型错误" tabindex="-1"><a class="header-anchor" href="#typeerror-对象-类型错误"><span>TypeError 对象（类型错误）</span></a></h4><p><code>TypeError</code>对象是<strong>变量或参数不是预期类型时发生的错误</strong>。比如，对字符串、布尔值、数值等原始类型的值使用<code>new</code>命令，就会抛出这种错误，因为<code>new</code>命令的参数应该是一个构造函数。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">new</span><span style="color:#D19A66;"> 123</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught TypeError: number is not a function</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 类型错误： 数字不是一个函数</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> obj</span><span style="color:#56B6C2;"> =</span><span style="color:#ABB2BF;"> {};</span></span>
<span class="line"><span style="color:#E5C07B;">obj</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">unknownMethod</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught TypeError: obj.unknownMethod is not a function</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 类型错误：obj.unknownMethod 不是一个函数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码的第二种情况，调用对象不存在的方法，也会抛出<code>TypeError</code>错误，因为<code>obj.unknownMethod</code>的值是<code>undefined</code>，而不是一个函数。</p><h4 id="urierror-对象-uri错误" tabindex="-1"><a class="header-anchor" href="#urierror-对象-uri错误"><span>URIError 对象 （URI错误）</span></a></h4><p><code>URIError</code>对象是 <strong>URI 相关函数的参数不正确时抛出的错误</strong>，主要涉及<code>encodeURI()</code>、<code>decodeURI()</code>、<code>encodeURIComponent()</code>、<code>decodeURIComponent()</code>、<code>escape()</code>和<code>unescape()</code>这六个函数。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#61AFEF;">decodeURI</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;%2&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// URIError: URI malformed</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="evalerror-对象-eval错误" tabindex="-1"><a class="header-anchor" href="#evalerror-对象-eval错误"><span>EvalError 对象 （eval错误）</span></a></h4><p><code>eval</code>函数没有被正确执行时，会抛出<code>EvalError</code>错误。该<strong>错误类型已经不再使用了，只是为了保证与以前代码兼容，才继续保留。</strong></p><h4 id="总结-开发者手动使用" tabindex="-1"><a class="header-anchor" href="#总结-开发者手动使用"><span>总结（开发者手动使用）</span></a></h4><p>以上这6种派生错误，连同原始的<code>Error</code>对象，都是构造函数。<strong>开发者可以使用它们，手动生成错误对象的实例</strong>。这些构造函数都接受一个参数，代表错误提示信息（message）。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> err1</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了！&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> err2</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> RangeError</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了，变量超出有效范围！&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> err3</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> TypeError</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了，变量类型无效！&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">err1</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#7F848E;font-style:italic;"> // &quot;出错了！&quot;</span></span>
<span class="line"><span style="color:#E5C07B;">err2</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#7F848E;font-style:italic;"> // &quot;出错了，变量超出有效范围！&quot;</span></span>
<span class="line"><span style="color:#E5C07B;">err3</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#7F848E;font-style:italic;"> // &quot;出错了，变量类型无效！&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3、自定义错误" tabindex="-1"><a class="header-anchor" href="#_3、自定义错误"><span>3、自定义错误</span></a></h3><p>除了 JavaScript 原生提供的七种错误对象，还可以定义自己的错误对象。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> UserError</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;font-style:italic;">message</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#56B6C2;"> =</span><span style="color:#E06C75;"> message</span><span style="color:#56B6C2;"> ||</span><span style="color:#98C379;"> &#39;默认信息&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E5C07B;">  this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> =</span><span style="color:#98C379;"> &#39;UserError&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">UserError</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">prototype</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(); </span><span style="color:#7F848E;font-style:italic;">// 原型继承 Error对象</span></span>
<span class="line"><span style="color:#E5C07B;">UserError</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">prototype</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">constructor</span><span style="color:#56B6C2;"> =</span><span style="color:#E06C75;"> UserError</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 使用</span></span>
<span class="line"><span style="color:#C678DD;">new</span><span style="color:#61AFEF;"> UserError</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;这是自定义的错误！&#39;</span><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码自定义一个错误对象<code>UserError</code>，让它继承<code>Error</code>对象。然后，就可以生成这种自定义类型的错误了。</p><h3 id="_4、throw-语句-中断程序并抛出错误" tabindex="-1"><a class="header-anchor" href="#_4、throw-语句-中断程序并抛出错误"><span>4、throw 语句 （中断程序并抛出错误）</span></a></h3><p><code>throw</code>语句的作用是<strong>手动中断程序执行，抛出一个错误</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> x</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">x</span><span style="color:#56B6C2;"> &lt;=</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#C678DD;">  throw</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;x 必须为正数&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught Error: x 必须为正数</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，如果变量<code>x</code>小于等于<code>0</code>，就手动抛出一个错误，告诉用户<code>x</code>的值不正确，整个程序就会在这里中断执行。可以看到，<code>throw</code>抛出的错误就是它的参数，这里是一个<code>Error</code>实例。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> UserError</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;font-style:italic;">message</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#56B6C2;"> =</span><span style="color:#E06C75;"> message</span><span style="color:#56B6C2;"> ||</span><span style="color:#98C379;"> &#39;默认信息&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#E5C07B;">  this</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> =</span><span style="color:#98C379;"> &#39;UserError&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">throw</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> UserError</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了！&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught UserError {message: &quot;出错了！&quot;, name: &quot;UserError&quot;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>throw</code>抛出的是一个<code>UserError</code>实例。</p><p>实际上，<code>throw</code>可以抛出任何类型的值。也就是说，它的参数可以是任何值。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#7F848E;font-style:italic;">// 抛出一个字符串</span></span>
<span class="line"><span style="color:#C678DD;">throw</span><span style="color:#98C379;"> &#39;Error！&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught Error！</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 抛出一个数值</span></span>
<span class="line"><span style="color:#C678DD;">throw</span><span style="color:#D19A66;"> 42</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught 42</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 抛出一个布尔值</span></span>
<span class="line"><span style="color:#C678DD;">throw</span><span style="color:#D19A66;"> true</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught true</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 抛出一个对象</span></span>
<span class="line"><span style="color:#C678DD;">throw</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">  toString</span><span style="color:#ABB2BF;">: </span><span style="color:#C678DD;">function</span><span style="color:#ABB2BF;"> () {</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#98C379;"> &#39;Error!&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">};</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught {toString: ƒ}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对于 JavaScript 引擎来说，<strong>遇到<code>throw</code>语句，程序就中止了</strong>。引擎会接收到<code>throw</code>抛出的信息，可能是一个错误实例，也可能是其他类型的值。</p><h3 id="_5、try-catch-结构-捕获错误-对错误进行处理-不中断" tabindex="-1"><a class="header-anchor" href="#_5、try-catch-结构-捕获错误-对错误进行处理-不中断"><span>5、try...catch 结构（捕获错误，对错误进行处理，不中断）</span></a></h3><p>一旦发生错误，程序就中止执行了。JavaScript 提供了<code>try...catch</code>结构，<strong>允许对错误进行处理</strong>，选择是否往下执行。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">  throw</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了!&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> +</span><span style="color:#98C379;"> &quot;: &quot;</span><span style="color:#56B6C2;"> +</span><span style="color:#E5C07B;"> e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">stack</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Error: 出错了!</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//   at &lt;anonymous&gt;:3:9</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//   ...</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>try</code>代码块抛出错误（上例用的是<code>throw</code>语句），JavaScript 引擎就立即把代码的执行，转到<code>catch</code>代码块，或者说错误被<code>catch</code>代码块捕获了。<code>catch</code>接受一个参数，表示<code>try</code>代码块抛出的值。</p><p>如果你不确定某些代码是否会报错，就可以把它们放在<code>try...catch</code>代码块之中，便于进一步对错误进行处理。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">  f</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  // 处理错误</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，如果函数<code>f</code>执行报错，就会进行<code>catch</code>代码块，接着对错误进行处理。</p><p><code>catch</code>代码块捕获错误之后，<strong>程序不会中断</strong>，会按照正常流程继续执行下去。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">  throw</span><span style="color:#98C379;"> &quot;出错了&quot;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">111</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#E5C07B;">console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">222</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 111</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 222</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>try</code>代码块抛出的错误，被<code>catch</code>代码块捕获后，程序会继续向下执行。</p><p><code>catch</code>代码块之中，还可以再抛出错误，甚至使用嵌套的<code>try...catch</code>结构。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> n</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> 100</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">  throw</span><span style="color:#E06C75;"> n</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#C678DD;">  if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#56B6C2;"> &lt;=</span><span style="color:#D19A66;"> 50</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">    // ...</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">else</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    throw</span><span style="color:#E06C75;"> e</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught 100</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>catch</code>代码之中又抛出了一个错误。</p><p>为了<strong>捕捉不同类型的错误</strong>，<code>catch</code>代码块之中可以加入判断语句。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">  foo</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">bar</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#C678DD;">  if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#C678DD;"> instanceof</span><span style="color:#E5C07B;"> EvalError</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> +</span><span style="color:#98C379;"> &quot;: &quot;</span><span style="color:#56B6C2;"> +</span><span style="color:#E5C07B;"> e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">else</span><span style="color:#C678DD;"> if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E06C75;">e</span><span style="color:#C678DD;"> instanceof</span><span style="color:#E5C07B;"> RangeError</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">name</span><span style="color:#56B6C2;"> +</span><span style="color:#98C379;"> &quot;: &quot;</span><span style="color:#56B6C2;"> +</span><span style="color:#E5C07B;"> e</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  // ...</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>catch</code>捕获错误之后，会判断错误类型（<code>EvalError</code>还是<code>RangeError</code>），进行不同的处理。</p><h3 id="_6、finally-代码块-在try-catch最后-必执行的" tabindex="-1"><a class="header-anchor" href="#_6、finally-代码块-在try-catch最后-必执行的"><span>6、finally 代码块（在try..catch最后，必执行的）</span></a></h3><p><code>try...catch</code>结构允许在最后添加一个<code>finally</code>代码块，表示<strong>不管是否出现错误，都必需在最后运行的语句</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> cleansUp</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    throw</span><span style="color:#C678DD;"> new</span><span style="color:#61AFEF;"> Error</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;出错了……&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;此行不会执行&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> { </span><span style="color:#7F848E;font-style:italic;">// 不管有没有出错都会执行finally</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;完成清理工作&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;此行不会执行&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">cleansUp</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 完成清理工作</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Uncaught Error: 出错了……</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at cleansUp (&lt;anonymous&gt;:3:11)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//    at &lt;anonymous&gt;:10:1</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 由于没有catch语句，所以会打印出错误信息，并中断除finally以外的代码。</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 如果有catch语句则会执行catch内的代码块，而不会打印错误信息。且不会中断代码。</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，由于没有<code>catch</code>语句块，一旦发生错误，代码就会中断执行。中断执行之前，会先执行<code>finally</code>代码块，然后再向用户提示报错信息。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> idle</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;font-style:italic;">x</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">x</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#98C379;"> &#39;result&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;FINALLY&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">idle</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;hello&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// hello</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// FINALLY</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>try</code>代码块没有发生错误，而且里面还包括<code>return</code>语句，但是<code>finally</code>代码块依然会执行。而且，这个函数的返回值还是<code>result</code>。</p><p>下面的例子说明，<code>return</code>语句的执行是排在<code>finally</code>代码之前，只是等<code>finally</code>代码执行完毕后才返回。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> count</span><span style="color:#56B6C2;"> =</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> countUp</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#E06C75;"> count</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E06C75;">    count</span><span style="color:#56B6C2;">++</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">countUp</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"><span style="color:#E06C75;">count</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 1</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码说明，<code>return</code>语句里面的<code>count</code>的值，是在<code>finally</code>代码块运行之前就获取了。</p><p>下面是<code>finally</code>代码块用法的<strong>典型场景</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#61AFEF;">openFile</span><span style="color:#ABB2BF;">(); </span><span style="color:#7F848E;font-style:italic;">// 打开文件</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">  writeFile</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">Data</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 写入文件</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#61AFEF;">  handleError</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 如果写入出错这处理错误</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">  closeFile</span><span style="color:#ABB2BF;">();</span><span style="color:#7F848E;font-style:italic;">// 不管是否出错都会执行关闭文件</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码首先打开一个文件，然后在<code>try</code>代码块中写入文件，如果没有发生错误，则运行<code>finally</code>代码块关闭文件；一旦发生错误，则先使用<code>catch</code>代码块处理错误，再使用<code>finally</code>代码块关闭文件。</p><p>下面的例子充分反映了<code>try...catch...finally</code>这三者之间的<strong>执行顺序</strong>。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> f</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">0</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">    throw</span><span style="color:#98C379;"> &#39;bug&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#D19A66;"> true</span><span style="color:#ABB2BF;">; </span><span style="color:#7F848E;font-style:italic;">// 这句原本会延迟到 finally 代码块结束再执行</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">2</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 不会运行</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">3</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#D19A66;"> false</span><span style="color:#ABB2BF;">; </span><span style="color:#7F848E;font-style:italic;">// 这句会覆盖掉前面那句 return</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">4</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 不会运行</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">5</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 不会运行</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">var</span><span style="color:#E06C75;"> result</span><span style="color:#56B6C2;"> =</span><span style="color:#61AFEF;"> f</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 0</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 1</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// 3</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E06C75;">result</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// false</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>catch</code>代码块结束执行之前，会先执行<code>finally</code>代码块。</p><p><code>catch</code>代码块之中，触发转入<code>finally</code>代码块的标志，不仅有<code>return</code>语句，还有<code>throw</code>语句。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">function</span><span style="color:#61AFEF;"> f</span><span style="color:#ABB2BF;">() {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    throw</span><span style="color:#98C379;"> &#39;出错了！&#39;</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;捕捉到内部错误&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">    throw</span><span style="color:#E06C75;"> e</span><span style="color:#ABB2BF;">; </span><span style="color:#7F848E;font-style:italic;">// 这句原本会等到finally结束再执行</span></span>
<span class="line"><span style="color:#ABB2BF;">  } </span><span style="color:#C678DD;">finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">    return</span><span style="color:#D19A66;"> false</span><span style="color:#ABB2BF;">; </span><span style="color:#7F848E;font-style:italic;">// 直接返回</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#61AFEF;">  f</span><span style="color:#ABB2BF;">(); </span><span style="color:#7F848E;font-style:italic;">// 接收到返回值false，并没有接收到错误</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">e</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">  // 此处不会执行</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;caught outer &quot;bogus&quot;&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">//  捕捉到内部错误</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，进入<code>catch</code>代码块之后，一遇到<code>throw</code>语句，就会去执行<code>finally</code>代码块，其中有<code>return false</code>语句，因此就直接返回了，不再会回去执行<code>catch</code>代码块剩下的部分了。</p><p><code>try</code>代码块内部，还可以再使用<code>try</code>代码块。</p><div class="language-js line-numbers-mode" data-highlighter="shiki" data-ext="js" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-js"><span class="line"><span style="color:#C678DD;">try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#C678DD;">  try</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    consle</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;Hello world!&#39;</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">// 报错，console拼错</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#C678DD;">  finally</span><span style="color:#ABB2BF;"> {</span></span>
<span class="line"><span style="color:#E5C07B;">    console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;Finally&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">  }</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">log</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;Will I run?&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">catch</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">error</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#E5C07B;">  console</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">error</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">error</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">message</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Finally</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// consle is not defined</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面代码中，<code>try</code>里面还有一个<code>try</code>。内层的<code>try</code>报错（<code>console</code>拼错了），这时会执行内层的<code>finally</code>代码块，然后抛出错误，被外层的<code>catch</code>捕获。</p><h2 id="四、console对象" tabindex="-1"><a class="header-anchor" href="#四、console对象"><span>四、console对象</span></a></h2><h3 id="console-time-console-timeend-用于计算程序的用时" tabindex="-1"><a class="header-anchor" href="#console-time-console-timeend-用于计算程序的用时"><span>console.time()，console.timeEnd() （用于计算程序的用时）</span></a></h3><p>这两个方法用于计时，可以算出一个操作所花费的准确时间。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="background-color:#282c34;color:#abb2bf;"><pre class="shiki one-dark-pro vp-code"><code class="language-"><span class="line"><span>console.time(&#39;Array initialize&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>var array= new Array(1000000);</span></span>
<span class="line"><span>for (var i = array.length - 1; i &gt;= 0; i--) {</span></span>
<span class="line"><span>  array[i] = new Object();</span></span>
<span class="line"><span>};</span></span>
<span class="line"><span></span></span>
<span class="line"><span>console.timeEnd(&#39;Array initialize&#39;);</span></span>
<span class="line"><span>// Array initialize: 1914.481ms</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>time</code>方法表示计时开始，<code>timeEnd</code>方法表示计时结束。它们的参数是计时器的名称。调用<code>timeEnd</code>方法之后，控制台会显示“计时器名称: 所耗费的时间”。</p><h2 id="文档" tabindex="-1"><a class="header-anchor" href="#文档"><span>文档</span></a></h2><p>学习文档：<a href="https://wangdoc.com/javascript/" target="_blank" rel="noopener noreferrer">https://wangdoc.com/javascript/</a></p>`,170)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};